INSERT INTO sport_translations (sport_id, locale, name, description) SELECT id, 'en', 'Athletics', 'Track and field events: races, jumps, throws and combined events.' FROM sports WHERE name = 'Athlétisme';
INSERT INTO sport_translations (sport_id, locale, name, description) SELECT id, 'de', 'Leichtathletik', 'Leichtathletik-Wettkämpfe: Lauf-, Sprung-, Wurfdisziplinen und Mehrkampf.' FROM sports WHERE name = 'Athlétisme';
INSERT INTO sport_translations (sport_id, locale, name, description) SELECT id, 'es', 'Atletismo', 'Pruebas de pista y campo: carreras, saltos, lanzamientos y pruebas combinadas.' FROM sports WHERE name = 'Athlétisme';

INSERT INTO sport_translations (sport_id, locale, name, description) SELECT id, 'en', 'Artistic Swimming', 'Aquatic discipline combining swimming, dance and acrobatics, performed in solo, duet and team.' FROM sports WHERE name = 'Natation artistique';
INSERT INTO sport_translations (sport_id, locale, name, description) SELECT id, 'de', 'Synchronschwimmen', 'Wasserdisziplin aus Schwimmen, Tanz und Akrobatik, ausgeführt als Solo, Duett und Mannschaft.' FROM sports WHERE name = 'Natation artistique';
INSERT INTO sport_translations (sport_id, locale, name, description) SELECT id, 'es', 'Natación artística', 'Disciplina acuática que combina natación, danza y acrobacias, en modalidad individual, dúo y equipo.' FROM sports WHERE name = 'Natation artistique';
